#!/usr/bin/env python3
"""Generate remaining examples to reach targets: CISA 200, Kaspersky 200, DFIR 200, SANS 150."""
import json, os

OUT = os.path.join(os.path.dirname(__file__), "raw")
SYS = "You are a ransomware forensic analyst with deep expertise in Windows internals and incident response."
AT, GM = "2026-03-17T11:00:00Z", "claude-opus-4-6"

def mk(src, url, sec, et, topics, pid, q, a):
    return {"messages":[{"role":"system","content":SYS},{"role":"user","content":q},{"role":"assistant","content":a}],
            "metadata":{"source":src,"source_url":url,"source_section":sec,"example_type":et,"topics":topics,
                        "generation_prompt_id":pid,"generated_at":AT,"generator_model":GM,"quality_score":None}}

def append(fname, items):
    with open(os.path.join(OUT, fname), "a") as f:
        for i in items: f.write(json.dumps(i, ensure_ascii=False)+"\n")
    return len(items)

def g(src, url, pid, data):
    return [mk(src,url,s,e,t,pid,q,a) for q,a,s,e,t in data]

def cisa_remaining():
    S,U,P="cisa_stopransomware","https://www.cisa.gov/stopransomware/ransomware-guide","cisa_qa_v6"
    return g(S,U,P,[
("What role does CISA's Cybersecurity Performance Goals (CPGs) play in ransomware defense?","CISA's CPGs provide a prioritized subset of cybersecurity practices that have the highest impact for reducing risk. For ransomware specifically, the CPGs include: detecting relevant threats and TTPs through monitoring of network and endpoint activity; implementing phishing-resistant MFA for all accounts with elevated privileges; maintaining and testing incident response plans; enabling logging for critical systems; segmenting networks to limit lateral movement; and validating that known exploited vulnerabilities are remediated promptly. CPGs differ from frameworks like NIST CSF by providing specific, measurable, prescriptive actions rather than broad capability goals.","CPG Framework","qa",["cpg","cisa_framework"]),
("How does Windows Credential Guard protect against ransomware credential theft?","Credential Guard uses virtualization-based security (VBS) to isolate LSASS secrets in a hardware-protected container inaccessible to even kernel-mode code. It protects: NTLM password hashes, Kerberos ticket-granting tickets, and credentials stored by applications as domain credentials. For ransomware prevention: Mimikatz and other LSASS dumping tools cannot access the isolated credentials, breaking the credential theft phase of the kill chain. Limitations: Credential Guard does not protect against Kerberoasting (which targets service tickets, not TGTs), does not protect credentials cached in individual applications, and requires compatible hardware (UEFI, TPM 2.0, Secure Boot). Enable via Group Policy at Computer Configuration > Administrative Templates > System > Device Guard > Turn On Virtualization Based Security.","Prevention Best Practices","qa",["credential_guard","endpoint_hardening"]),
("What common mistakes do organizations make during ransomware incident response?","Common IR mistakes include: powering off infected systems before capturing memory (losing encryption keys and volatile evidence); immediately reimaging systems without forensic preservation; communicating incident details over potentially compromised corporate email where the attacker may be monitoring; focusing solely on the encrypted systems while ignoring the broader compromise; restoring from backups without first eradicating the attacker's persistence mechanisms (leading to re-encryption); announcing containment prematurely before all compromised systems are identified; failing to reset the KRBTGT password allowing Golden Ticket persistence; treating the incident as purely an IT problem without engaging legal, communications, and business leadership; and underestimating the scope by assuming encryption is the only impact without investigating data exfiltration.","Response Checklist","qa",["ir_mistakes","lessons_learned"]),
("How do you use the Windows Security Event ID 4663 for file access auditing during ransomware investigation?","Event ID 4663 records successful file and registry object access when auditing is enabled via SACL (System Access Control List) on the object. For ransomware: configure SACLs on canary files to detect early encryption activity; audit sensitive directories containing financial data, PII, or intellectual property to detect attacker data reconnaissance; and audit backup infrastructure access to detect unauthorized attempts to delete or modify backups. Key fields: the Subject (who accessed the file), Object Name (file path), Access Mask (type of access: ReadData 0x1, WriteData 0x2, AppendData 0x4, Delete 0x10000), and Process Name (which executable performed the access). Limitations: Event ID 4663 generates high log volumes when enabled broadly, so target SACLs to specific high-value directories rather than entire volumes.","Forensic Investigation","qa",["file_auditing","access_monitoring"]),
("What are the forensic implications of ransomware that reboots systems into Safe Mode?","Some ransomware variants (BlackBasta, Snatch, REvil) reboot into Safe Mode to execute encryption without EDR interference. Forensic artifacts: bcdedit commands in process creation logs setting safeboot option; Event ID 1074 (System Shutdown/Restart) showing the initiated restart; Event ID 6005/6006 in System log marking system startup/shutdown; in Safe Mode, fewer services start, so Event ID 7036 (service state changes) will show reduced service activity. Key implications: EDR agents typically do not start in Safe Mode, creating telemetry gaps during the encryption phase; the encryption timestamp in Safe Mode correlates with system boot time rather than the bcdedit command time; and the bcdedit modification itself (which precedes the restart) occurs while EDR is still active, providing a detection window.","Forensic Investigation","qa",["safe_mode","defense_evasion"]),
("How should organizations configure Windows Firewall logging for ransomware detection?","Windows Firewall logs (C:\\Windows\\System32\\LogFiles\\Firewall\\pfirewall.log) record allowed and dropped connections. Configuration via GPO: enable logging for both allowed and dropped connections; set maximum log size to at least 32MB with circular overwrite; log path should be on a dedicated logging volume if possible. For ransomware detection: analyze dropped connections for: port scanning activity (many dropped connections from a single source to sequential ports), lateral movement attempts blocked by firewall rules (SMB, RDP to workstations), and C2 connection attempts blocked by egress rules. Analyze allowed connections for: unusual SMB connections between workstations, RDP sessions to servers from non-admin workstations, and WinRM connections from unexpected sources. Parse firewall logs with: Windows Firewall Parser, custom PowerShell scripts, or import into SIEM for correlation.","Prevention Best Practices","qa",["firewall_logging","network_monitoring"]),
("What is the CISA recommendation for managing remote access infrastructure to prevent ransomware?","CISA recommends: never expose RDP, SMB, or management interfaces directly to the internet; require VPN or ZTNA for all remote access with phishing-resistant MFA enforced; configure VPN to allow split-tunnel only for authorized resources (full-tunnel VPN for sensitive access); implement time-limited VPN sessions with forced re-authentication; deploy VPN anomaly detection monitoring for: connections from unusual geolocations, simultaneous connections from different locations, and connections at unusual hours. For management infrastructure: place all management interfaces (firewall admin, switch management, backup console, hypervisor management) on a dedicated management VLAN accessible only from Privileged Access Workstations; never expose management interfaces to the general corporate network or the internet; and implement jump servers with session recording for all administrative access to critical infrastructure.","Prevention Best Practices","qa",["remote_access","infrastructure_security"]),
("How do forensic investigators distinguish between ransomware encryption and legitimate file encryption?","Distinguishing characteristics: ransomware encryption affects many file types simultaneously across multiple directories, while legitimate encryption typically targets specific files or folders; ransomware adds uniform file extensions or renames files with a consistent pattern, while legitimate encryption tools maintain original filenames; ransomware creates ransom notes in every encrypted directory; ransomware typically deletes shadow copies before encryption while legitimate encryption does not; ransomware encryption increases Shannon entropy to near-maximum (7.95-8.0) for all file types uniformly, while legitimate encryption tools may preserve original file extensions or use recognizable container formats; and ransomware encryption occurs rapidly across the file system while legitimate encryption is usually applied to specific datasets. Timeline analysis helps: check if shadow copy deletion or security tool disabling preceded the encryption, which is unique to ransomware.","Forensic Investigation","qa",["encryption_identification","forensic_methodology"]),
("What are the CISA-recommended steps for securely rebuilding systems after ransomware?","CISA recommends rebuilding rather than cleaning infected systems. Steps: use clean installation media (not the system's recovery partition which may be compromised); apply all current security patches before connecting to any network; install EDR and verify it is operational before domain join; change the local administrator password to a unique value (LAPS will manage subsequent rotations); join the system to the rebuilt domain infrastructure; apply hardened security baselines via Group Policy; install only required applications from trusted sources; restore user data from verified clean backups (verified to predate the intrusion); and monitor the rebuilt system closely for 30 days for any indicators of re-compromise. For servers: rebuild from golden images where possible; restore application data from backups tested for integrity; reconfigure applications from documented configurations rather than importing settings from compromised systems; and validate functionality in an isolated staging environment before connecting to production.","Response Checklist","instruction",["system_rebuild","recovery_procedure"]),
("What evidence helps determine whether ransomware used the Windows CryptoAPI or custom encryption?","CryptoAPI usage leaves distinct artifacts: imports of advapi32.dll functions (CryptAcquireContext, CryptGenKey, CryptEncrypt, CryptDestroyKey) visible in the PE import table; and Event ID 5061 in Security log if Audit System Security is enabled records cryptographic operations including key generation and destruction. BCrypt API usage: imports of bcrypt.dll functions (BCryptGenerateSymmetricKey, BCryptEncrypt) in the PE import table. Custom encryption: no system crypto API imports; instead, the binary contains embedded encryption routines identifiable through: constant values characteristic of specific algorithms (AES S-box, ChaCha20 constants), custom key scheduling code, and direct memory manipulation for encryption operations. OpenSSL usage (Royal/BlackSuit): links to OpenSSL libraries with imports like EVP_EncryptInit_ex, EVP_EncryptUpdate; may statically link OpenSSL, making the binary larger. The encryption method affects decryption feasibility: CryptoAPI usage with improper key management may be exploitable, while properly implemented custom encryption is not.","Forensic Investigation","qa",["crypto_analysis","encryption_methods"]),
("How do you investigate a ransomware incident that affected VMware vCenter in addition to standard Windows infrastructure?","vCenter compromise extends the attack surface to all managed VMs. Investigation: check vCenter audit logs (vpxd-*.log in /var/log/vmware/vpxd/) for authentication events from unauthorized sources, VM power state changes, and configuration modifications. Check for: compromised vCenter service accounts used to access the vSphere web client; VM snapshots deleted by the attacker to prevent snapshot-based recovery; storage policies modified to remove VM-level replication; and newly created VMs that may serve as attacker footholds. On ESXi hosts managed by vCenter: verify SSH access logs (/var/log/auth.log) for unauthorized shell access; check whether DCUI (Direct Console User Interface) access was enabled or passwords were changed; and examine whether VMFS datastore permissions were modified. Recovery: rebuild vCenter from scratch rather than restoring from a compromised backup; change all vCenter and ESXi root/admin passwords; and verify that ESXi hosts' lockdown mode and SSH access are properly configured. Important: vCenter compromise gives the attacker the ability to access any VM's virtual console without the VM's OS credentials.","Forensic Investigation","qa",["vcenter_investigation","virtual_infrastructure"]),
    ])

def kaspersky_remaining():
    S,U,P="kaspersky_securelist","https://securelist.com/modern-ransomware-groups-ttps/106824/","kaspersky_qa_v6"
    return g(S,U,P,[
("How do ransomware groups use legitimate penetration testing tools in their operations?","Ransomware operators extensively use tools designed for legitimate security testing. Cobalt Strike: the most prevalent C2 framework, providing beacon implants, lateral movement, credential theft, and remote administration; cracked versions are widely available despite Fortra's licensing enforcement. Metasploit: used for exploitation and payload generation; Meterpreter shells provide flexible post-exploitation. BloodHound: AD attack path visualization originally developed for defenders; SharpHound collector provides comprehensive AD relationship mapping. Mimikatz: credential extraction tool originally developed for security research; integrated into Cobalt Strike as a built-in module. Rubeus: Kerberos interaction tool for Kerberoasting, AS-REP Roasting, and ticket manipulation. CrackMapExec/NetExec: SMB enumeration and credential validation across networks. Impacket: Python-based tools for remote execution, credential dumping, and relay attacks. The dual-use nature of these tools means detection cannot rely on signature-based blocking alone; behavioral detection of how these tools are used (context, timing, target patterns) is essential.","Tool Abuse","passage",["dual_use_tools","penetration_testing"]),
("What are the technical differences between Ransomware-as-a-Service (RaaS) platforms?","RaaS platforms differ in: encryptor capabilities (encryption speed, cross-platform support, configurable modes); affiliate management (panel features, payment processing, reputation systems); infrastructure (leak site design, negotiation portal, C2 options provided to affiliates); builder customization (what parameters affiliates can configure: file extensions, kill lists, excluded directories, encryption mode); affiliate requirements (some platforms vet affiliates while others are open); payment models (percentage split, flat fee per successful attack, or subscription-based); and operational support (some provide deployment guidance, others expect self-sufficient affiliates). LockBit's panel was highly automated with chat-based negotiation; BlackCat provided sophisticated configurable payloads; Hive offered a straightforward affiliate interface; and smaller operations like Akira provide more personalized affiliate support.","Ransomware Ecosystem","qa",["raas_comparison","platform_analysis"]),
("How do ransomware groups maintain operational security while running their infrastructure?","Ransomware operational security includes: hosting infrastructure on bulletproof hosting providers in jurisdictions with limited law enforcement cooperation; using Tor hidden services for all victim-facing infrastructure; separating roles so that affiliates do not have access to the core infrastructure or other affiliates' operations; using cryptocurrency (primarily Bitcoin and Monero) with mixing services for payment processing; maintaining separate identities for different operations; communicating through encrypted channels (Jabber/XMPP with OMEMO, Tox, or custom encrypted chat); and avoiding targeting organizations in CIS countries which could attract attention from Russian-speaking law enforcement. OpSec failures documented by researchers include: reuse of infrastructure IP addresses across campaigns, timezone leaks in forum posts and code artifacts, linguistic patterns in communications enabling profiling, metadata in documents and tools revealing developer information, and operational mistakes like leaving Rclone configs with personal cloud accounts on victim systems.","Threat Intelligence","passage",["opsec","infrastructure_analysis"]),
("How has the exploitation of zero-day vulnerabilities by ransomware groups evolved?","Zero-day exploitation by ransomware groups represents an escalation in capability. Historical pattern: ransomware groups traditionally exploited known vulnerabilities (N-days) with available patches that organizations had not applied. Evolution: Clop pioneered mass zero-day exploitation with Accellion FTA (2020), GoAnywhere MFT (CVE-2023-0669), and MOVEit Transfer (CVE-2023-34362), affecting thousands of organizations simultaneously. This approach: eliminates the need for phishing or credential theft, bypasses network-based defenses since the vulnerability is in an internet-facing appliance, enables simultaneous multi-victim operations, and provides immediate access to sensitive data stored in file transfer systems. Other groups have followed: LockBit affiliates exploited Citrix Bleed (CVE-2023-4966) before it was widely patched; Akira targeted Cisco VPN zero-days; and various groups exploited Ivanti VPN vulnerabilities in 2024. Implications for defenders: vulnerability management must go beyond patch management to include: asset discovery for all internet-facing services, virtual patching via WAF rules, and network segmentation that limits the impact even if an edge device is compromised.","Threat Evolution","passage",["zero_day","vulnerability_exploitation"]),
("What TTPs distinguish financially motivated ransomware groups from state-sponsored groups using ransomware?","Financial groups: focused on speed and volume of attacks; target organizations based on perceived ability to pay; use standard RaaS toolkits; negotiate for payment and provide decryptors when paid; and avoid targets that would attract disproportionate law enforcement attention. State-sponsored groups: may use ransomware as a cover for espionage (APT41); may deploy destructive wiper malware disguised as ransomware (NotPetya by Sandworm, WhisperGate targeting Ukraine); target specific sectors aligned with state intelligence objectives; may not actually provide decryption even if payment is made; demonstrate higher operational sophistication including supply chain compromise; and maintain persistent access beyond the ransomware deployment. Forensic differentiation: examine whether the encryption is recoverable (wipers masquerading as ransomware use irrecoverable destruction); check for espionage-related activity (data exfiltration of specific strategic information rather than broad financial data); and assess whether the targeting pattern aligns with geopolitical objectives rather than financial opportunity.","Threat Classification","qa",["nation_state_vs_criminal","attribution"]),
("How do ransomware groups perform pre-attack reconnaissance on potential victims?","Pre-attack reconnaissance determines targeting decisions and ransom demands. External reconnaissance: querying public financial databases for victim revenue (Dun & Bradstreet, SEC filings for public companies); checking cyber insurance databases or broker listings to assess payment likelihood; scanning internet-facing infrastructure for vulnerabilities using Shodan, Censys, or automated scanning; harvesting employee credentials from previous breaches via dark web databases; and reviewing LinkedIn for IT staff details that inform social engineering approaches. Internal reconnaissance (post-compromise): running net commands and AD queries to map the organizational structure; accessing financial documents on file shares to determine actual revenue; checking email for insurance policy details and financial statements; and assessing backup infrastructure to determine recovery capability. This intelligence shapes: ransom demand amount (typically 1-5% of perceived annual revenue); negotiation strategy (knowledge of insurance coverage influences their approach); and attack timing (targeting periods of high business activity or known IT staffing gaps).","Operational Intelligence","qa",["victim_reconnaissance","targeting_decisions"]),
("What forensic indicators help identify which specific ransomware affiliate conducted an attack?","Affiliate identification goes beyond payload analysis to examine operational tradecraft. Indicators: tool preferences (specific Cobalt Strike malleable profiles, preferred reconnaissance tools, unique PowerShell scripts); infrastructure patterns (C2 server hosting providers, domain registration patterns, SSL certificate characteristics); operational timing (working hours suggesting timezone, activity patterns suggesting single vs. team operation); TTP consistency (an affiliate who always uses AnyDesk rather than ScreenConnect, or always uses WMI rather than PsExec for lateral movement); and specific OpSec mistakes (reused infrastructure from previous attacks, distinctive command syntax, or identifiable custom tools). Cross-incident correlation: compare IOCs against commercial threat intelligence for known affiliate tracking; check for overlapping infrastructure with previous incidents; and compare the complete TTP profile against documented affiliate behaviors. Attribution value: identifying the affiliate helps predict their next actions (based on their established playbook), assess the reliability of their decryptors (based on previous victims' experiences), and provide intelligence to law enforcement for potential disruption.","Forensic Analysis","qa",["affiliate_identification","attribution"]),
("How do ransomware operators handle the transition from the initial loader to the hands-on-keyboard phase?","The transition from automated loader (IcedID, QakBot, BumbleBee) to manual operation is a critical attack phase with distinct forensic indicators. The loader typically: establishes initial C2 communication with its own infrastructure; performs automated reconnaissance (system info, domain membership, network configuration); and sends the gathered intelligence to the operator for victim evaluation. Transition indicators: the loader process creates a new process or injects into an existing process (Sysmon Event ID 8/CreateRemoteThread) to deploy the second-stage C2 framework (Cobalt Strike, Sliver, Brute Ratel); new C2 traffic appears to a different destination than the loader's original C2; manual commands appear in the timeline (net commands, AdFind, BloodHound) that are inconsistent with automated loader behavior; and the tempo of activity changes from rapid automated reconnaissance to deliberate, human-paced exploration. Detection opportunity: the handoff creates a time window (minutes to hours) where both the loader's C2 and the new framework's C2 are active simultaneously, providing two independent detection opportunities.","Kill Chain Analysis","qa",["loader_handoff","operational_transition"]),
("What are the key indicators that differentiate ransomware encryption from a destructive wiper attack?","Distinguishing ransomware from wipers is critical for response strategy. Ransomware indicators: ransom note dropped in affected directories; consistent file extension change across affected files; intact file metadata in $MFT (files are renamed/modified, not destroyed); encryption that preserves file size (or increases it slightly due to encryption padding); the original file structure is maintained (just the content is encrypted); and the attacker provides a communication channel for negotiation. Wiper indicators: no ransom note or a fake ransom note with non-functional payment mechanism; file contents overwritten with zeros, random data, or repeated patterns rather than encrypted; $MFT corruption or destruction; partition table or boot record destruction (Petya-style wipers); file sizes changed to zero or uniform values; and no functional decryption mechanism provided. Investigation: check a sample of encrypted files: if the file size is preserved and the entropy is uniformly near 8.0, it is likely encryption; if files are truncated, filled with zeros, or have corrupted metadata, it is likely wiping. The distinction matters because: ransomware may be recoverable through decryptors, while wiped data requires backup restoration; and wiper attacks may indicate nation-state involvement with different attribution and response implications.","Forensic Analysis","qa",["wiper_vs_ransomware","malware_classification"]),
("How do different ransomware groups handle multi-domain Active Directory environments?","Multi-domain environments present both opportunity and complexity for ransomware operators. Domain trust enumeration: operators use nltest /domain_trusts to map trust relationships between domains; BloodHound maps attack paths across trust boundaries. Cross-domain movement techniques: using trust keys extracted via DCSync to forge inter-realm TGTs; exploiting SIDHistory to add privileged SIDs from the target domain to a compromised account; leveraging unconstrained delegation systems that can impersonate any user in the trusting domain; and using shared service accounts that have privileges in multiple domains. Deployment strategy: operators typically compromise one domain fully, then pivot to trusted domains for maximum impact; ransomware deployment may be staggered across domains or simultaneous depending on the group's capability. Investigation: map all trust relationships early in the investigation; investigate each domain independently as the compromise level may differ; check for inter-realm Kerberos activity (Event ID 4769 with cross-domain service tickets); and examine SIDHistory attributes for unauthorized additions. Recovery: KRBTGT must be reset independently in each domain; trust relationships should be rebuilt only after both domains are confirmed clean.","Domain Operations","qa",["multi_domain","trust_exploitation"]),
("Describe how ransomware groups target backup software specifically and the forensic indicators of backup destruction.","Backup infrastructure targeting is systematic and deliberate. Software-specific targeting: Veeam (most commonly targeted): operators look for Veeam configuration databases containing backup repository credentials, target VeeamBR and VeeamMount services for stopping, and attempt to delete backup files from repositories. Commvault: operators target the CommServe database and media agents. Windows Server Backup: wbadmin delete catalog -quiet and wbadmin delete systemstatebackup commands. Veritas BackupExec: targeting beremote.exe processes and backup data directories. Forensic indicators: process creation logs showing backup service termination (net stop VeeamBR, taskkill targeting backup processes); file system activity showing deletion of backup files (.vbk, .vib for Veeam; .bkf for Windows Backup); registry modifications disabling backup services from starting; and Event ID 7036 showing backup services entering stopped state. Advanced techniques: attackers with backup admin credentials may use the backup software's own interface to delete backup jobs and retention policies, leaving audit trails within the backup software's logs. Detection: monitor backup service health independently from the backup infrastructure itself; alert on any backup job failures or policy modifications.","Impact Phase","qa",["backup_targeting","data_destruction"]),
    ])

def dfir_remaining():
    S,U,P="dfir_report","https://thedfirreport.com/","dfir_qa_v6"
    return g(S,U,P,[
("How do you identify process injection using Sysmon Event ID 8 and 10?","Event ID 8 (CreateRemoteThread) records when a process creates a thread in another process, a primary mechanism for Cobalt Strike injection. Key fields: SourceProcessId (the injecting process), TargetProcessId (the target process), NewThreadId, StartAddress, and StartFunction. Alert on: CreateRemoteThread from non-OS processes targeting legitimate processes; injection targeting lsass.exe (credential theft) or svchost.exe/explorer.exe (persistence). Event ID 10 (ProcessAccess) records when a process opens another process for access. Key fields: SourceProcessId, TargetProcessId, and GrantedAccess. For credential theft detection: filter for TargetImage containing lsass.exe with GrantedAccess values including 0x1010 (PROCESS_VM_READ + PROCESS_QUERY_INFORMATION) or 0x1FFFFF (PROCESS_ALL_ACCESS). Combine both events: Event ID 8 followed by Event ID 10 from the same source targeting the same destination creates a high-confidence injection alert.","Forensic Analysis","qa",["process_injection","sysmon_events"]),
("What are the key indicators of Kerberoasting activity in Windows event logs?","Kerberoasting detection centers on Event ID 4769 (Kerberos service ticket request) from domain controller Security logs. Key indicators: Ticket Encryption Type 0x17 (RC4-HMAC) rather than AES (0x12 or 0x11); modern environments should use AES, so RC4 requests are anomalous. Service Name targeting accounts with SPNs that are service accounts (not computer accounts which normally use Kerberos). Source IP from a workstation rather than the server hosting the service. High volume of service ticket requests for different SPNs from a single source in a short timeframe (Kerberoasting tools enumerate all available SPNs). False positive reduction: exclude computer account SPNs (HOST/ and other machine SPNs); exclude known service-to-service authentication; and baseline normal Kerberos activity per system.","Forensic Analysis","qa",["kerberoasting","credential_access"]),
("How should you investigate evidence of ransomware operators accessing sensitive file shares?","File share access investigation combines multiple evidence sources. On the file server: Event ID 5140 (share accessed) provides the share name, source IP, and account; Event ID 5145 (detailed file share) provides individual file access records with operation types. On the attacker's system: ShellBags in UsrClass.dat record network paths browsed through Explorer; LNK files in Recent Items reference UNC paths to accessed files; MRU lists in NTUSER.DAT may contain share paths; and Thumbcache databases may contain thumbnails of previewed documents. Network evidence: SMB connections visible in firewall logs and NetFlow data showing the data volume transferred. Analysis approach: use Event ID 5145 to build a complete list of files accessed by the attacker (filter by source IP and account known to be compromised); assess the sensitivity of accessed data by matching file paths against the organization's data classification scheme; and determine whether files were read-only accessed (reconnaissance) or also downloaded (exfiltration staging).","Forensic Analysis","qa",["share_access","data_reconnaissance"]),
("Describe the forensic artifacts of RunDLL32 abuse for malware execution.","Rundll32.exe is heavily abused by ransomware operators for executing malicious DLLs while appearing as a legitimate Windows process. Forensic indicators of abuse: process creation (Event ID 4688/Sysmon Event ID 1) showing rundll32.exe with: DLL paths in user-writable directories (Downloads, Temp, AppData); unusual export function names (DllRegisterServer from a non-COM DLL, or random function names); command-line containing encoded or obfuscated parameters; and no command-line arguments at all (indicating reflective injection rather than legitimate DLL loading). Parent process analysis: legitimate rundll32 usage is typically spawned by explorer.exe (user action), svchost.exe (system), or application installers; suspicious parents include: cmd.exe, PowerShell, wscript.exe, mshta.exe, or Office applications. Network activity: rundll32.exe making outbound network connections is almost always malicious (legitimate DLL operations rarely require network access). Sysmon Event ID 7 (ImageLoaded): unsigned DLLs loaded by rundll32.exe from non-system directories are high-confidence indicators.","Forensic Analysis","qa",["rundll32_abuse","execution_analysis"]),
("How do you detect and investigate PowerShell Empire usage in ransomware operations?","PowerShell Empire creates distinctive forensic artifacts despite being primarily memory-resident. Delivery: Empire stagers are typically delivered via macro documents, HTA files, or command-line PowerShell; the stager script appears in PowerShell Script Block Logging (Event ID 4104) containing: base64-encoded payload, IEX (Invoke-Expression) execution, and HTTP/S download cradles pointing to the Empire C2 server. Communication: Empire uses HTTP/S for C2 with configurable User-Agent strings and URI paths; connections follow a polling pattern similar to Cobalt Strike beaconing. Module execution: Empire modules run PowerShell commands that appear in Script Block Logging; common modules include: Invoke-Mimikatz (credential theft), Invoke-BloodHound (AD reconnaissance), Invoke-SMBExec (lateral movement), and Invoke-Kerberoast. Detection: monitor for base64-encoded PowerShell with IEX; look for PowerShell establishing persistent HTTP/S connections; and search for Empire-specific strings in Script Block Logging (Empire's agent has identifiable code patterns).","Forensic Analysis","qa",["powershell_empire","c2_detection"]),
("What investigation steps are needed when ransomware has encrypted a Hyper-V environment?","Hyper-V ransomware investigation requires examining both the host and virtual machine layers. On the Hyper-V host: check for ransomware artifacts in the standard Windows forensic locations (Event Logs, Prefetch, MFT); examine Hyper-V event logs (Microsoft-Windows-Hyper-V-VMMS-Operational) for VM power state changes initiated by the attacker; check for modifications to VM settings (memory, CPU) that may indicate the attacker preparing VMs for encryption; and examine the VHDX/VHD files for encryption (check if file headers still contain the correct magic bytes). VM-specific investigation: if VMs are still accessible, collect forensic artifacts from within each VM; if VMs are encrypted, check Hyper-V checkpoints (equivalent to VMware snapshots) which may predate the encryption; and examine the storage location configuration to determine if all VHDX files were on the same volume. Recovery: Hyper-V checkpoints may provide recovery points; VHDX files may be partially recoverable if the attacker only encrypted the beginning of the file; and replica VMs on a secondary host may be unaffected if replication was active.","Forensic Analysis","qa",["hyperv_forensics","virtual_infrastructure"]),
("How do DFIR investigations handle cases where the attacker had root access to Linux-based network appliances?","Linux appliance compromise (firewalls, VPN concentrators, load balancers) requires specialized investigation. Evidence collection: SSH authentication logs (/var/log/auth.log or /var/log/secure); shell command history (~/.bash_history, ~/.ash_history for embedded systems); system logs (/var/log/syslog, /var/log/messages); cron configuration (/etc/crontab, /var/spool/cron/); installed packages and modifications to system binaries; kernel module listing (lsmod) for rootkit detection; and network configuration changes (iptables rules, routing tables, NAT configuration). Investigation focus: determine if the appliance was used as: a pivot point for accessing internal networks; a persistent backdoor bypassing network security controls; a traffic interception point (packet capture or proxy configuration added by attacker); or the initial entry point (exploitation of the appliance's management interface). Common attacker modifications: added SSH authorized_keys for persistent access; modified firewall rules to allow inbound access; installed reverse shells in cron jobs; and modified routing to redirect traffic.","Forensic Analysis","qa",["linux_appliance","network_device_compromise"]),
("What forensic techniques help identify the ransomware operator's data selection process before exfiltration?","Understanding data selection reveals the attacker's objectives and helps assess exfiltration scope. File access pattern analysis: Event ID 5145 on file servers shows the attacker's browsing and file access patterns; ShellBags from the attacker's RDP session show which directories were explored; and browser history may show the attacker searching for files via intranet portals. Staging directory analysis: examine temporary directories (C:\\ProgramData, C:\\Users\\Public) for: WinRAR/7-Zip command execution showing which directories were compressed; recently created archive files revealing the data selected for exfiltration; and naming patterns of archives that may indicate content categorization. Keyword-based selection: some groups use automated scripts that search for keywords (password, financial, SSN, confidential, contract); PowerShell scripts in Script Block Logging may reveal these search patterns. Volume analysis: compare SRUM network data volumes with the known size of sensitive data directories to estimate the completeness of exfiltration. Evidence of selectivity indicates a sophisticated operator who reviewed the data before exfiltrating, versus bulk copying which suggests less targeted operations.","Forensic Analysis","qa",["data_selection","exfiltration_scope"]),
("How do you investigate ransomware that used Windows Management Instrumentation (WMI) for persistence?","WMI persistence investigation requires examining multiple evidence sources. Active subscriptions: query using PowerShell Get-CimInstance -Namespace root/subscription -ClassName __EventFilter, __EventConsumer, and __FilterToConsumerBinding. WMI repository forensics: parse C:\\Windows\\System32\\wbem\\Repository\\OBJECTS.DATA using WMI-Forensics or python-cim to extract all subscriptions including deleted ones; this file contains both active and remnant subscription data with embedded timestamps. Event log evidence: WMI-Activity/Operational log Event ID 5861 records WMI provider operations; and Sysmon Event IDs 19 (WmiEventFilter), 20 (WmiEventConsumer), and 21 (WmiEventConsumerToFilter) specifically track WMI persistence creation. Common ransomware WMI patterns: CommandLineEventConsumer executing PowerShell encoded commands at system startup; ActiveScriptEventConsumer running VBScript that downloads and executes payloads; and __TimerEvent triggers that execute at regular intervals (C2 check-in persistence).","Forensic Analysis","qa",["wmi_persistence","event_subscription"]),
("How do you correlate Sysmon DNS query events with process execution for C2 identification?","Sysmon Event ID 22 (DNSQuery) records DNS queries with process attribution, enabling direct correlation between DNS activity and specific processes. Correlation approach: filter Event ID 22 for queries made by non-browser processes to identify unexpected DNS resolution (e.g., rundll32.exe, svchost.exe, or unknown executables resolving external domains); correlate the queried domain with the process's subsequent network connections (Sysmon Event ID 3) to confirm the query led to a C2 connection; build a per-process DNS resolution profile showing all domains each process queried during the attack window. C2 identification: processes resolving multiple domains that resolve to the same IP (potential DNS round-robin C2); processes resolving domains not matching their expected function (svchost.exe resolving non-Microsoft domains); processes resolving domains with high entropy or DGA-like patterns; and processes making DNS queries at regular intervals (C2 beacon DNS resolution). Create a lookup table mapping: process name, queried domain, resolved IP, query timestamp, and subsequent connection to enable comprehensive C2 infrastructure mapping.","Forensic Analysis","qa",["dns_correlation","c2_identification"]),
    ])

def sans_remaining():
    S,U,P="sans_dfir","https://www.sans.org/posters/dfir-cheatsheet-booklet/","sans_qa_v6"
    return g(S,U,P,[
("What is the SANS methodology for conducting dead-box forensic analysis of a ransomware-encrypted system?","Dead-box analysis examines a powered-off system without altering its state. Procedure: connect the evidence drive to a forensic workstation using a hardware write-blocker; create a forensic image (E01 format with SHA256 verification); mount the image in a forensic platform (Autopsy, FTK, X-Ways). Even on encrypted systems: the $MFT remains intact and parseable, providing complete file metadata including timestamps for all files (encrypted and unencrypted); Windows Event Logs (.evtx files) survive encryption and can be exported and analyzed; registry hives are typically unencrypted and contain Shimcache, Amcache references, services, Run keys, and other persistence artifacts; Prefetch files survive and provide execution evidence; and the pagefile/hiberfil.sys may contain memory content including potential encryption keys. Analysis workflow: parse $MFT first for timeline construction; process Event Logs with Chainsaw/Hayabusa for automated detection; parse registry hives with RECmd/Registry Explorer; analyze Prefetch with PECmd; and build a consolidated timeline using Timeline Explorer.","Forensic Methodology","qa",["dead_box","offline_analysis"]),
("How should forensic analysts document their analysis process for legal defensibility?","Legal defensibility requires meticulous documentation. Contemporaneous notes: maintain a forensic examination log recording every action taken with: timestamp, action performed, tool used (including version), parameters/options selected, hash values computed, and results observed. Tool validation: document tool versions and maintain records showing the tool has been validated for forensic use; for open-source tools, note the specific version and download hash. Evidence handling: maintain chain of custody for all physical and digital evidence; record hash values at every transfer point; and document any anomalies encountered during analysis. Analysis methodology: describe the analytical approach used and why specific artifacts were prioritized; note alternative explanations considered and why they were excluded. Report structure: clearly distinguish between observed facts (what the evidence shows), analytical conclusions (what the evidence means), and opinions (assessments based on experience); and state any limitations of the analysis.","Legal Requirements","qa",["documentation","legal_defensibility"]),
("What are the key considerations for forensic analysis in a legal hold or litigation context after ransomware?","Legal hold considerations include: preservation scope must cover all potentially relevant evidence (not just the encrypted systems but also network logs, email, backup records, and incident response documentation); forensic images must be created before any remediation actions; working copies must be used for all analysis, with original evidence preserved untouched; all analysis must be documented sufficiently for expert testimony; and the analysis may need to support multiple legal proceedings simultaneously (criminal prosecution, civil litigation, regulatory investigation, insurance claims). Special requirements: forensic examiners may need to provide testimony about their qualifications, methodology, and findings; reports may be subject to discovery rules requiring disclosure to opposing parties; and attorney-client privilege considerations may affect what communications can be included in the forensic record. Data retention: maintain all evidence, working copies, and analysis artifacts until all potential legal proceedings are resolved, which may be years after the incident.","Legal Requirements","qa",["legal_hold","litigation_support"]),
("How do you use Velociraptor's VQL for fleet-wide ransomware artifact collection?","VQL (Velociraptor Query Language) enables custom artifact collection across all endpoints simultaneously. Key VQL hunts for ransomware investigation: search for ransom notes across the fleet: SELECT FullPath, Mtime FROM glob(globs='C:\\\\**\\\\README*.txt') WHERE Size < 50000 AND Mtime > timestamp(epoch='2026-03-10'); search for known attacker tool hashes: SELECT * FROM Artifact.Generic.Detection.Yara.Glob(PathGlob='C:\\\\**\\\\*.exe', YaraRule=rule_content); check for recently created scheduled tasks: SELECT * FROM Artifact.Windows.System.TaskScheduler() WHERE Created > timestamp(epoch='2026-03-10'); identify systems with disabled Windows Defender: SELECT * FROM Artifact.Windows.Detection.MpPreference() WHERE DisableRealtimeMonitoring=TRUE; collect Prefetch data fleet-wide: SELECT * FROM Artifact.Windows.Forensics.Prefetch() WHERE Executable =~ '(?i)(mimikatz|psexec|rclone|adfind)'; and check for recently installed services: SELECT * FROM Artifact.Windows.System.Services() WHERE Created > timestamp(epoch='2026-03-10'). Each hunt runs across all enrolled endpoints and returns results to the central Velociraptor server within minutes.","Fleet Analysis","qa",["velociraptor_vql","fleet_hunting"]),
("What are the SANS-recommended rapid assessment questions for the first 15 minutes of a ransomware incident?","The first 15 minutes should answer critical scoping questions. (1) Is encryption actively spreading? Check EDR for new detections and file server audit logs for ongoing mass file modifications; this determines whether emergency containment is needed immediately. (2) What systems are affected? Query EDR for ransomware file hashes and ransom note filenames across the fleet; check for the ransom note on network shares using PowerShell. (3) What is the ransomware variant? Examine the ransom note text and file extension; upload to ID Ransomware for identification. (4) Are domain controllers compromised? Check DC health, authentication functionality, and GPO integrity. (5) Are backups intact? Verify that backup infrastructure is accessible and recent backup jobs completed successfully; check immutable/offline copies. (6) Is there evidence of data exfiltration? Quick check of proxy logs for large outbound transfers and known cloud storage destinations. (7) What is the likely initial access vector? Check for recent VPN anomalies, phishing reports, and vulnerability exploitation indicators. These answers enable the incident commander to make informed initial containment and communication decisions.","Incident Response","qa",["rapid_assessment","first_response"]),
("How do you analyze Windows Defender Antivirus detection logs for understanding the attack timeline?","Windows Defender logs in Microsoft-Windows-Windows Defender/Operational provide chronological detection data. Event ID 1116 (malware detected by real-time protection) records: Threat Name (family identification), Severity, Category, Path (file location of detected malware), Process Name (executing process), and Detection Time. Event ID 1117 (action taken on detected malware) shows: what action Defender took (quarantined, removed, allowed) and whether it succeeded. Timeline analysis: chronologically order all Defender detection events during the attack window; the earliest detection often represents the initial malware arrival, even if the attacker subsequently disabled Defender; later detections (if any) show attacker tools that were deployed before Defender was disabled. Critical insight: if Defender Event ID 5001 (real-time protection disabled) appears in the timeline, note the timestamp; all subsequent attacker activity occurred without endpoint protection. Map the Defender detection timeline against the attacker activity timeline to understand: which tools were detected (providing attacker capability intelligence), which tools were missed, and when the attacker achieved sufficient access to disable protection.","Forensic Analysis","qa",["defender_timeline","detection_analysis"]),
("What forensic value does the Windows Security Account Manager (SAM) database provide in ransomware investigations?","The SAM database (C:\\Windows\\System32\\config\\SAM) stores local user account information. Forensic value: local account enumeration reveals all local accounts including: recently created rogue accounts (compare account creation dates against the attack timeline); enabled accounts that were previously disabled (attackers may re-enable built-in accounts like Guest or DefaultAccount); and local administrator account password change dates (indicating whether the attacker reset local admin passwords). Password hash analysis: if the SAM and SYSTEM hives are collected together, password hashes can be extracted and compared against common password databases to assess password strength; reuse of hashes across systems indicates LAPS is not deployed. Account metadata: last logon timestamps for local accounts help determine which accounts were actively used during the attack; account flags show which accounts have 'Password Never Expires' or 'User Cannot Change Password' configured; and SID history may contain entries from other domains indicating trust exploitation. Parse with Registry Explorer or use secretsdump.py (offline) against the collected SAM and SYSTEM hives.","Forensic Analysis","qa",["sam_analysis","account_forensics"]),
("How do you use CyberChef for quick forensic data analysis during ransomware incident response?","CyberChef (gchq.github.io/CyberChef/) is a web-based data transformation tool useful for rapid forensic analysis. Common ransomware IR uses: decode base64-encoded PowerShell commands extracted from Event ID 4104 logs (paste the encoded string, apply 'From Base64' recipe); convert ROT13-encoded UserAssist entries to readable text (apply 'ROT13' recipe); calculate file entropy to determine if a file is encrypted (apply 'Entropy' recipe; values near 8.0 indicate encryption); decode XOR-obfuscated strings from malware configs (apply 'XOR Brute Force' recipe); extract URLs, email addresses, and IP addresses from memory dumps or log files (apply 'Extract URLs', 'Extract email addresses', 'Extract IPs' recipes); convert timestamps between formats (apply 'Translate DateTime Format' for Windows FILETIME to human-readable); and generate file hashes for IOC comparison (apply 'SHA-256', 'SHA-1', 'MD5' recipes). CyberChef recipes can be chained together for multi-step decoding operations, making it invaluable for processing obfuscated attacker commands and configurations found during investigation.","Analysis Tools","qa",["cyberchef","data_analysis"]),
    ])

